+        topic, [&, command, expected](std_srvs::Trigger::Request& req, std_srvs::Trigger::Response& resp) {
+          resp.message = this->client_.sendAndReceive(command);
+          resp.success = std::regex_match(resp.message, std::regex(expected));
+          return true;
+        });
